import kotlinx.datetime.*
import kotlinx.datetime.format.*
import kotlin.test.*

class ErrorMessagesTest {
    @Test
    fun testAmPmInconsistency() {
        val format = LocalTime.Format {
            hour()
            char(':')
            minute()
            char(' ')
            amPmMarker("AM", "PM")
        }
        val error = assertFailsWith<DateTimeFormatException> { format.parse("23:00 AM") }
        println("Actual AM/PM error: ${error.message}")
        assertTrue(error.message!!.contains("23:00 AM"), "Message should contain input")
        assertTrue(error.message!!.contains("Inconsistent hour and the AM/PM marker"), "Message should contain cause")
    }

    @Test
    fun testConstructorValidation() {
        val format = LocalTime.Format {
            hour()
            char(':')
            minute()
        }
        val error = assertFailsWith<DateTimeFormatException> { format.parse("12:60") }
        println("Actual Constructor error: ${error.message}")
        assertTrue(error.message!!.contains("12:60"), "Message should contain input")
    }

    @Test
    fun testExpectedOneOf() {
         val format = LocalTime.Format {
            hour()
            char(':')
            minute()
            char(' ')
            amPmMarker("AM", "PM")
        }
        val error = assertFailsWith<DateTimeFormatException> { format.parse("10:00 XY") }
        println("Actual OneOf error: ${error.message}")
        // Expected: "Position 6: Expected one of [AM, PM] but got XY"
        assertTrue(error.message!!.contains("Expected one of"), "Message should contain 'Expected one of', got: ${error.message}")
    }
}
"}

